var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_NPC_NANAHARA2_E","text":{"KOREA":"침식체 섬멸 확인. 침식파 계수도 꾸준히 감소하고 있습니다.","JPN":"侵食体の殲滅を確認。侵食波係数もどんどん減少しています。","ENG":"C.O. termination confirmed. Corruption ray level decreasing.","TWN":"侵蝕體確認殲滅，侵蝕波係數也持續減少中。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_NPC_NANAHARA2_E","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다들 고생하셨어요. 피해가 더 커지기 전에 해결되어 다행입니다.","JPN":"みなさん、お疲れさまでした。被害が大きくなる前に解決できてよかったです。","ENG":"Good work, everyone. I am relieved things ended before they got out of hand.","TWN":"大家都辛苦了，幸好在傷亡擴大前處理完畢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"정말 감사합니다. 다른 지역도 이제 대부분 소강상태라는군요.","JPN":"本当にありがとうございます。他の地域ももうほとんどが小康状態のようです。","ENG":"Thank you so much. I hear most of the other areas are cleared as well.","TWN":"真的非常感謝，其他地區的情況大部分也都已經和緩下來。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"상처 부위는 아직 괜찮으신가요?","JPN":"傷の方は大丈夫ですか？","ENG":"How is your wound?","TWN":"你受傷的地方還好嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"네, 치료해주신 덕분에……","JPN":"はい、治療してくださったおかげで……","ENG":"Good, thanks to you...","TWN":"是，多虧你替我治療……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"저기, 떠나기 전에 하나만 물어봐도 되겠습니까?","JPN":"あの、出発される前に一つだけ聞いてもいいですか？","ENG":"Um, would you mind if I ask you something before you leave?","TWN":"那個，離開前我可以問一個問題嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 말씀하세요.","JPN":"はい、どうぞ。","ENG":"No, please do.","TWN":"當然，你請問。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"얼마 전부터 침식사태 때마다 활약을 하고 있다던데, 왜 태스크포스에 소속되지도 않은 분들이 이런 위험한 일을 도우시는 거죠?","JPN":"少し前から侵食事態が発生するたびにご活躍されているようですが、どうしてタスクフォースにも所属していない方たちがこのような危険な仕事を手伝っているのですか？","ENG":"I hear that you’ve been helping us with the Corruption disasters. Why? You’re not even a TASKFORCE.","TWN":"我聽說從前陣子開始，每次發生侵蝕事件時你們都會出手相助，你們又不屬於特遣勢力，為什麼願意不顧生命危險幫我們呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That is...","TWN":"那是因為……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희에게는 그런 책임을 질 의무가 있기 때문입니다.","JPN":"私たちにはそのような責任を取る義務があるからです。","ENG":"That is because we are responsible for it.","TWN":"我們有義務擔負起這個責任。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_A","text":{"KOREA":"네? 대체 누가 초자연적인 재해를 두고 사람에게 책임을 묻습니까?","JPN":"はい？　いったい誰が超自然的な災害で人に責任を問うんですか？","ENG":"Huh? Why would anyone be responsible for a supernatural disaster?","TWN":"什麼？有誰會拿超自然的災難向人究責呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희의 대비가 미흡한 탓에 풀려나서는 안 될 악이 깨어났고, 그 여파로 침식의 경계가 약해진 것이니까요.","JPN":"私たちの備えが不十分だったせいで解放されてはならない悪が目覚め、そのあおりで侵食の境界が脆くなっているのですから。","ENG":"It is because we were unprepared, which led to the awakening of a great evil. That is why the Corruption boundaries weakened.","TWN":"因為我們的疏失，喚醒禁忌的惡，才會導致侵蝕的警戒變弱。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"……뭐, 어떤 사정이 있는지 모르겠지만 그런 죄 지은 표정은 짓지 마세요.","JPN":"……まあ、どんな事情があるのかは知りませんが、そんな罪を犯したような顔をしないでください。","ENG":"...I don’t know what your story is, but don’t feel so guilty about it.","TWN":"……嗯，雖然我不清楚究竟發生什麼事，但請你不要一臉愧疚的樣子。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"저희에게 당신들은 영웅이니까요.","JPN":"私たちにとってあなたたちは英雄なんですから。","ENG":"You’re a hero to us.","TWN":"因為對我們來說，你們是英雄。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_A","text":{"KOREA":"그럼요. 시민들도 고마워할 겁니다.","JPN":"そうです。市民も感謝してるはずですよ。","ENG":"Of course. Even the civilians would be grateful.","TWN":"是啊，市民也會很感謝你們的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런데, 저 분들은?","JPN":"ところで、あの方々は？","ENG":"Oh, by the way, who are those people?","TWN":"不過，他們是誰？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"아, 노아라는 이름의 신생 태스크포스입니다. 침식이 재발하지 않도록 침식 쐐기를 제거하는 뒤처리 전문반이죠.","JPN":"ああ、ノアという新生タスクフォースです。侵食が再発しないように侵食楔を取り除く、いわば後始末の専門班ですね。","ENG":"They are a new TASKFORCE called NOA. They are in charge of destroying the Corrupted Wedges, so that the disaster doesn’t happen again.","TWN":"喔，他們是新興的特遣勢力，叫作諾亞，專門負責清除侵蝕釘，以防再次發生侵蝕事件。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"수고 많았소. 이제부터 여긴 우리가 맡도록 하지.","JPN":"ご苦労だった。ここからは我らが担当しよう。","ENG":"Well done. You may leave the rest to us.","TWN":"辛苦了，接下來這裡就交給我們吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L32_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_A","text":{"KOREA":"그럼 뒤는 부탁드립니다. 저흰 이만 철수할 테니까요.","JPN":"それでは、後をお願いします。私たちはもう引き上げますので。","ENG":"Thank you. We’ll be going now.","TWN":"那後續就麻煩你們了，我們先撤退。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"우리도 이만 돌아가도록 하자, 치후유.","JPN":"私たちも戻りましょう、千冬。","ENG":"Let us go back, Chifuyu.","TWN":"千冬，那我們也回去吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……네, 당주님.","JPN":"……はい、当主。","ENG":"...Yes, Lady Nanahara.","TWN":"……是，堂主。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_QM","text":{"KOREA":"흐음, 적성체는 한 명이라고 하더니 둘이네요.","JPN":"ふーん、適合する標本は一人と聞きましたが、二人なんですね。","ENG":"Hmm, I thought there was only one suitable sample... However, there are two of them.","TWN":"嗯？合適的標本不是一個嗎？怎麼變二個？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_QM","text":{"KOREA":"감히 아버지에게 거짓말을 한 걸까요?","JPN":"身の程もしらずお父様に嘘をついたのでしょうか。","ENG":"Did he dare lie to you?","TWN":"他竟敢欺騙爸爸？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"그 자의 착각이겠지. 육안으로 그릇의 적합성을 판별하는 건 불가능할 테니.","JPN":"あの者の勘違いだろう。肉眼で器の適合性を判別することは不可能だ。","ENG":"Must be a mistake. It is impossible to identify the adequacy of a vessel with plain eyesight.","TWN":"應該是他弄錯吧，畢竟要用肉眼判斷是不是合適的器皿是不可能的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LENORE_UNION_NULL_QM","text":{"KOREA":"후훗, 적성인자의 후보군인 원본이 둘씩이나.","JPN":"ふふっ、クリムゾン・ファクターに適合する候補者であるオリジナルが二人もいるなんて。","ENG":"Fu fu. Two Originals fit for the embedded factor?","TWN":"呵呵，符合適神因子的候選人竟然有二個。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_QM","text":{"KOREA":"이대로 보내기엔 아쉬운데…… 어떻게 할까요, 아버지?","JPN":"このまま行かせるのはちょっと惜しい気もしますが……どうされますか、お父様。","ENG":"I hope not to let them go like this... What do you say, father?","TWN":"父親，就這樣放她們走未免太可惜……要怎麼做呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L45_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"산출된 결과물이 원본에 비해 우성인지 열성인지……","JPN":"産出された結果物がオリジナルに比べ優性か劣性か……","ENG":"Whether the result is superior or inferior compared to the Original...","TWN":"究竟計算的結果與正本相比是強是弱……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"조금은 미리 시험을 해보는 것도 나쁘지 않겠지.","JPN":"少し前もって試してみるのも悪くないだろう。","ENG":"Perhaps it would be a good notion to experiment.","TWN":"現在先稍微測試一下似乎也不錯。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};